import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef, type ComponentRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Alert.module.css';

type AlertStatus = 'neutral' | 'info' | 'success' | 'warning' | 'error';

type AlertRootProps = HTMLArkProps<'div'> & {
  status?: AlertStatus;
};

const AlertRoot = forwardRef<ComponentRef<typeof ark.div>, AlertRootProps>(function AlertRoot(
  { children, className, role, status = 'neutral', ...props },
  ref,
) {
  return (
    <ark.div
      ref={ref}
      role={role ?? (status === 'error' ? 'alert' : 'status')}
      data-scope="alert"
      data-part="root"
      data-slot="alert-root"
      data-status={status}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    >
      {children}
    </ark.div>
  );
});

const AlertIndicator = forwardRef<ComponentRef<typeof ark.span>, HTMLArkProps<'span'>>(
  function AlertIndicator({ className, ...props }, ref) {
    return (
      <ark.span
        ref={ref}
        data-scope="alert"
        data-part="indicator"
        data-slot="alert-indicator"
        aria-hidden="true"
        className={clsx(styles.indicator, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertContent = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertContent({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="content"
        data-slot="alert-content"
        className={clsx(styles.content, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertTitle = forwardRef<ComponentRef<typeof ark.p>, HTMLArkProps<'p'>>(function AlertTitle(
  { className, ...props },
  ref,
) {
  return (
    <ark.p
      ref={ref}
      data-scope="alert"
      data-part="title"
      data-slot="alert-title"
      className={clsx(styles.title, normalizeClassName(className))}
      {...props}
    />
  );
});

const AlertDescription = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertDescription({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="description"
        data-slot="alert-description"
        className={clsx(styles.description, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AlertActions = forwardRef<ComponentRef<typeof ark.div>, HTMLArkProps<'div'>>(
  function AlertActions({ className, ...props }, ref) {
    return (
      <ark.div
        ref={ref}
        data-scope="alert"
        data-part="actions"
        data-slot="alert-actions"
        className={clsx(styles.actions, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const Alert = Object.assign(AlertRoot, {
  Root: AlertRoot,
  Indicator: AlertIndicator,
  Content: AlertContent,
  Title: AlertTitle,
  Description: AlertDescription,
  Actions: AlertActions,
});

export { Alert };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    grid-template-columns: auto minmax(0, 1fr);
    align-items: start;
    width: 100%;
    min-width: 0;
    row-gap: var(--alert-content-gap, var(--spacing-1));
    column-gap: var(--alert-gap, var(--spacing-3));
    border: var(--alert-border-width, var(--border-width-sm)) solid
      var(--alert-border-color, var(--alert-border-color-default, var(--color-border)));
    border-radius: var(--alert-radius, var(--radius-lg));
    padding: var(--alert-padding, var(--spacing-3));
    background-color: var(--alert-bg, var(--alert-bg-default, var(--color-card)));
    color: var(--alert-color, var(--alert-color-default, var(--color-card-foreground)));
    box-shadow: var(--alert-shadow, none);

    > [data-part='title'],
    > [data-part='description'] {
      grid-column: 2;
    }

    &[data-status='neutral'] {
      --alert-bg-default: var(--color-card);
      --alert-border-color-default: var(--color-border);
      --alert-color-default: var(--color-card-foreground);
      --alert-indicator-color-default: var(--color-muted-foreground);
    }

    &[data-status='info'] {
      --alert-bg-default: color-mix(in oklab, var(--color-primary) 4%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-primary) 32%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-indicator-color-default: var(--color-primary);
    }

    &[data-status='success'] {
      --alert-bg-default: color-mix(in oklab, var(--color-success) 10%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-success) 34%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-indicator-color-default: var(--color-success);
    }

    &[data-status='warning'] {
      --alert-bg-default: color-mix(in oklab, var(--color-warning) 13%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-warning) 38%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-indicator-color-default: var(--color-warning);
    }

    &[data-status='error'] {
      --alert-bg-default: color-mix(in oklab, var(--color-destructive) 9%, var(--color-background));
      --alert-border-color-default: color-mix(in oklab, var(--color-destructive) 35%, transparent);
      --alert-color-default: var(--color-foreground);
      --alert-indicator-color-default: var(--color-destructive);
    }

    &:not(:has(> [data-part='indicator'])) {
      grid-template-columns: minmax(0, 1fr);

      > [data-part='content'],
      > [data-part='title'],
      > [data-part='description'] {
        grid-column: 1;
      }
    }
  }

  .indicator {
    display: inline-flex;
    width: var(--alert-indicator-size, 1rem);
    height: var(--alert-indicator-size, 1rem);
    align-items: center;
    justify-content: center;
    color: var(--alert-indicator-color, var(--alert-indicator-color-default, currentColor));
    margin-block-start: var(--alert-indicator-offset, 0.125rem);

    & :where(svg) {
      width: var(--alert-indicator-size, 1rem);
      height: var(--alert-indicator-size, 1rem);
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .content {
    display: grid;
    min-width: 0;
    gap: var(--alert-content-gap, var(--spacing-1));
  }

  .title {
    margin: 0;
    min-width: 0;
    color: var(--alert-title-color, var(--alert-color, var(--alert-color-default)));
    font-size: var(--alert-title-font-size, var(--text-sm));
    font-weight: var(--alert-title-font-weight, var(--weight-semibold));
    line-height: var(--alert-title-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;
  }

  .description {
    min-width: 0;
    color: var(--alert-description-color, var(--color-muted-foreground));
    font-size: var(--alert-description-font-size, var(--text-sm));
    line-height: var(--alert-description-line-height, var(--line-height-text-sm));
    overflow-wrap: anywhere;

    & > :first-child {
      margin-top: 0;
    }

    & > :last-child {
      margin-bottom: 0;
    }
  }

  .actions {
    display: flex;
    flex-wrap: wrap;
    margin-block-start: var(--alert-actions-margin-top, var(--spacing-2));
    gap: var(--alert-actions-gap, var(--spacing-2));
  }
}
